class Solution:
    def solve(self, graph: List[List[int]]) -> bool:
        visited = [False] * len(graph)
        stack = [0] * len(graph)
        time = 0
        low = [0] * len(graph)
        parent = [-1] * len(graph)

        for i in range(len(graph)):
            if not visited[i]:
                if self.dfs(graph, i, 0, 0, -1, visited, stack, time, low, parent):
                    return True
        return False

    def dfs(self, graph, node, time, low, parent, visited, stack, time, low, parent):
        visited[node] = True
        low[node] = time + 1
        stack[time] = node
        time += 1
        parent[node] = -1

        for neighbor in graph[node]:
            if not visited[neighbor]:
                if self.dfs(graph, neighbor, time, low, parent, visited, stack, time, low, parent):
                    return True
                low[node] = min(low[node], low[neighbor])
                if low[neighbor] >= stack[time - 1]:
                    return True
            elif neighbor != parent[node]:
                if low[neighbor] >= stack[time - 1]:
                    return True
        stack[time - 1] = -1
        return False

if __name__ == '__main__':
    graph = [[1, 2], [0, 2, 3], [0, 3], [1, 2]]
    solution = Solution()
    print(solution.solve(graph))

