#include <iostream>
#include <vector>
#include <queue>

class Solution {
public:
    bool solve(std::vector<std::vector<int>>& graph) {
        std::vector<bool> visited(graph.size(), false);
        std::vector<int> stack(graph.size(), -1);
        int time = 0;
        int low[graph.size()];
        int parent[graph.size()];

        for (int i = 0; i < graph.size(); i++) {
            if (!visited[i]) {
                if (dfs(graph, i, 0, 0, -1, visited, stack, time, low, parent)) {
                    return true;
                }
            }
        }
        return false;
    }

    bool dfs(std::vector<std::vector<int>>& graph, int node, int time, int low, int parent, std::vector<bool>& visited, std::vector<int>& stack, int& time, int low[], int parent[]) {
        visited[node] = true;
        low[node] = time + 1;
        stack[time] = node;
        time++;
        parent[node] = -1;

        for (int neighbor : graph[node]) {
            if (!visited[neighbor]) {
                if (dfs(graph, neighbor, time, low, parent, visited, stack, time, low, parent)) {
                    return true;
                }
                low[node] = std::min(low[node], low[neighbor]);
                if (low[neighbor] >= stack[time - 1]) {
                    return true;
                }
            } else if (neighbor != parent[node]) {
                if (low[neighbor] >= stack[time - 1]) {
                    return true;
                }
            }
        }
        stack[time - 1] = -1;
        return false;
    }
};

int main() {
    std::vector<std::vector<int>> graph = {{1, 2}, {0, 2, 3}, {0, 3}, {1, 2}};
    Solution solution;
    std::cout << std::boolalpha << solution.solve(graph) << std::endl;
    return 0;
}
